changeSet.sql:
CREATE INDEX IF NOT EXISTS idx_megaset_name_trgm ON mega_set USING GIN (lower(name) gin_trgm_ops);
CREATE INDEX IF NOT EXISTS idx_megaset_description_trgm ON mega_set USING GIN (lower(coalesce(description, '')) gin_trgm_ops);
CREATE INDEX IF NOT EXISTS idx_megaset_notes_trgm ON mega_set USING GIN (lower(coalesce(notes, '')) gin_trgm_ops);
CREATE INDEX IF NOT EXISTS idx_megaset_set_number_trgm ON mega_set USING GIN (lower(set_number) gin_trgm_ops);
CREATE INDEX IF NOT EXISTS idx_megaset_attributes_text_trgm ON mega_set USING GIN (lower(coalesce(attributes::text, '')) gin_trgm_ops);
